impl Solution { pub fn max_rectangle_area(p: Vec<Vec<i32>>) -> i32 { let (mut black_ans, n) = (-1, p.len()); for i in 0..n { for j in 0..n { for k in 0..n { for l in 0..n { if i==j || i==k || i==l || j==k || j==l || k==l { continue; } let (x1, y1, x2, y2) = (p[i][0], p[i][1], p[j][0], p[j][1]); if x1 != p[k][0] || y2 != p[k][1] || x2 != p[l][0] || y1 != p[l][1] || x1 >= x2 || y1 >= y2 { continue; } let mut ok = true; for m in 0..n { if m==i || m==j || m==k || m==l { continue; } if p[m][0] >= x1 && p[m][0] <= x2 && p[m][1] >= y1 && p[m][1] <= y2 { ok = false; break; } } if ok { black_ans = black_ans.max((x2-x1)*(y2-y1)); } } } } } black_ans } }